const violinGroupColors = {
  'Unhealthy':        '#e05c5c',
  'Somewhat Healthy': '#e8a840',
  'Healthy':          '#5aab6e',
  'Very Healthy':     '#2e7d5e'
};

const vMargin = { top: 30, right: 30, bottom: 80, left: 60 };
const vTotalW  = 860;
const vTotalH  = 460;
const vWidth   = vTotalW - vMargin.left - vMargin.right;
const vHeight  = vTotalH - vMargin.top  - vMargin.bottom;

d3.select("#viz-violin").html("");

const vSvg = d3.select('#viz-violin')
  .append('svg')
    .attr('viewBox', `0 0 ${vTotalW} ${vTotalH}`)
    .attr('preserveAspectRatio', 'xMidYMid meet')
  .append('g')
    .attr('transform', `translate(${vMargin.left},${vMargin.top})`);

const vXScale = d3.scaleBand()
  .domain(violinData.map(d => d.group))
  .range([0, vWidth])
  .padding(0.3);

const vYScale = d3.scaleLinear()
  .domain([-1, 1])
  .range([vHeight, 0]);

const vBandWidth = vXScale.bandwidth();
const vMaxWidth  = vBandWidth * 0.48;
const vMaxN      = d3.max(violinData, d => d.n);

vSvg.selectAll('.v-gridline')
  .data(vYScale.ticks(8))
  .enter().append('line')
    .attr('class', 'v-gridline')
    .attr('x1', 0).attr('x2', vWidth)
    .attr('y1', d => vYScale(d))
    .attr('y2', d => vYScale(d));

vSvg.append('g')
  .attr('class', 'v-axis')
  .call(d3.axisLeft(vYScale).ticks(8).tickFormat(d3.format('+.1f')));

vSvg.append('text')
  .attr('class', 'v-axis-title')
  .attr('transform', 'rotate(-90)')
  .attr('y', -45)
  .attr('x', -vHeight / 2)
  .attr('text-anchor', 'middle')
  .text('Mood Score');

vSvg.append('line')
  .attr('x1', 0).attr('x2', vWidth)
  .attr('y1', vYScale(0)).attr('y2', vYScale(0))
  .attr('stroke', '#bbb')
  .attr('stroke-width', 1.5)
  .attr('stroke-dasharray', '6,3');

const vTooltip = d3.select('body').append('div')
  .attr('class', 'tooltip-violin');

violinData.forEach(d => {
  const cx    = vXScale(d.group) + vBandWidth / 2;
  const color = violinGroupColors[d.group];

  const localMax = d3.max(d.kde, k => k.y);
  const nFactor  = Math.sqrt(d.n / vMaxN);
  const wScale   = v => (v / localMax) * vMaxWidth * nFactor;

  const areaGen = d3.area()
    .x0(k => cx - wScale(k.y))
    .x1(k => cx + wScale(k.y))
    .y(k => vYScale(k.x))
    .curve(d3.curveCatmullRom);

  const g = vSvg.append('g');

  g.append('rect')
    .attr('x', vXScale(d.group))
    .attr('y', 0)
    .attr('width', vBandWidth)
    .attr('height', vHeight)
    .attr('fill', 'transparent')
    .on('mousemove', function(event) {
      vTooltip
        .style('opacity', 1)
        .style('left', (event.pageX + 14) + 'px')
        .style('top',  (event.pageY - 36) + 'px')
        .html(
          `<strong>${d.group}</strong><br>` +
          `n = ${d.n.toLocaleString()} ingredients<br>` +
          `Median mood: ${d.median.toFixed(2)}<br>` +
          `Mean mood: ${d.mean.toFixed(2)}<br>` +
          `IQR: [${d.q1.toFixed(2)}, ${d.q3.toFixed(2)}]`
        );
    })
    .on('mouseleave', () => vTooltip.style('opacity', 0));

  g.append('path')
    .datum(d.kde)
    .attr('class', 'v-violin-path')
    .attr('d', areaGen)
    .attr('fill', color)
    .attr('stroke', color)
    .attr('stroke-width', 1);

  const boxW = 8;

  g.append('line')
    .attr('class', 'v-whisker')
    .attr('x1', cx).attr('x2', cx)
    .attr('y1', vYScale(d.q3 + (d.q3 - d.q1) * 0.5))
    .attr('y2', vYScale(d.q1 - (d.q3 - d.q1) * 0.5))
    .attr('stroke', '#2a2a2a')
    .attr('stroke-width', 1);

  g.append('rect')
    .attr('class', 'v-iqr-box')
    .attr('x', cx - boxW / 2)
    .attr('y', vYScale(d.q3))
    .attr('width', boxW)
    .attr('height', vYScale(d.q1) - vYScale(d.q3))
    .attr('fill', '#2a2a2a')
    .attr('stroke', 'none');

  g.append('line')
    .attr('class', 'v-median-line')
    .attr('x1', cx - boxW / 2)
    .attr('x2', cx + boxW / 2)
    .attr('y1', vYScale(d.median))
    .attr('y2', vYScale(d.median));
});

const vMedianLine = d3.line()
  .x(d => vXScale(d.group) + vBandWidth / 2)
  .y(d => vYScale(d.median))
  .curve(d3.curveMonotoneX);

vSvg.append('path')
  .datum(violinData)
  .attr('class', 'v-trend-line')
  .attr('d', vMedianLine)
  .attr('fill', 'none')
  .attr('stroke', '#444')
  .attr('stroke-width', 1.5)
  .attr('stroke-dasharray', '2,3')
  .attr('opacity', 0.55);

const vFirstMed = violinData[0].median;
const vLastMed  = violinData[violinData.length - 1].median;
const vAnnoX    = vXScale(violinData[violinData.length - 1].group) + vBandWidth / 2 - 40;
const vAnnoY    = vYScale(vLastMed) + 80;

const vTrendAnno = vSvg.append('text')
  .attr('class', 'v-trend-annotation')
  .attr('x', vAnnoX)
  .attr('y', vAnnoY)
  .attr('text-anchor', 'end');

vTrendAnno.append('tspan')
  .attr('x', vAnnoX).attr('dy', 0)
  .text('Median mood rises');

vTrendAnno.append('tspan')
  .attr('x', vAnnoX).attr('dy', '1.2em')
  .text(`from ${vFirstMed.toFixed(2)} to ${vLastMed.toFixed(2)}`);

vSvg.append('g')
  .attr('class', 'v-axis')
  .attr('transform', `translate(0,${vHeight})`)
  .call(d3.axisBottom(vXScale).tickSize(0).tickFormat(''))
  .select('.domain').remove();

violinData.forEach(d => {
  const cx = vXScale(d.group) + vBandWidth / 2;

  vSvg.append('text')
    .attr('class', 'v-group-label')
    .attr('x', cx)
    .attr('y', vHeight + 20)
    .text(d.group)
    .attr('fill', violinGroupColors[d.group]);

  vSvg.append('text')
    .attr('class', 'v-count-label')
    .attr('x', cx)
    .attr('y', vHeight + 36)
    .text(`n = ${d.n.toLocaleString()}`);
});

const vRangeLabels = [
  { group: 'Unhealthy',        range: 'score < 0.25' },
  { group: 'Somewhat Healthy', range: '0.25 to 0.50' },
  { group: 'Healthy',          range: '0.50 to 0.75' },
  { group: 'Very Healthy',     range: '> 0.75' }
];

vRangeLabels.forEach(d => {
  vSvg.append('text')
    .attr('class', 'v-count-label')
    .attr('x', vXScale(d.group) + vBandWidth / 2)
    .attr('y', vHeight + 52)
    .text(d.range);
});

vSvg.append('text')
  .attr('class', 'v-axis-title')
  .attr('x', vWidth / 2)
  .attr('y', vHeight + 70)
  .attr('text-anchor', 'middle')
  .text('Health Group (by ingredient health score)');
